import{_ as t,c as a,o,a1 as r}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Intégration Bear : Sauvegarde automatique des plans | Plannotator","description":"Apprenez à configurer l'intégration Bear de plannotator. Sauvegardez automatiquement les plans approuvés via x-callback-url, génération intelligente de tags, capitalisation des connaissances et archivage des plans.","frontmatter":{"title":"Intégration Bear : Sauvegarde automatique des plans | Plannotator","sidebarTitle":"Sauvegarde auto vers Bear","subtitle":"Intégration Bear : Sauvegarde automatique des plans approuvés | Plannotator","description":"Apprenez à configurer l'intégration Bear de plannotator. Sauvegardez automatiquement les plans approuvés via x-callback-url, génération intelligente de tags, capitalisation des connaissances et archivage des plans.","tags":["Intégration","Bear","Application de notes","Capitalisation des connaissances"],"prerequisite":["start/installation-claude-code","platforms/plan-review-basics"],"order":3},"headers":[],"relativePath":"fr/backnotprop/plannotator/advanced/bear-integration/index.md","filePath":"fr/backnotprop/plannotator/advanced/bear-integration/index.md"}`),n={name:"fr/backnotprop/plannotator/advanced/bear-integration/index.md"};function i(l,e,s,d,p,u){return o(),a("div",null,[...e[0]||(e[0]=[r(`<h1 id="integration-bear-sauvegarde-automatique-des-plans-approuves" tabindex="-1">Intégration Bear : Sauvegarde automatique des plans approuvés <a class="header-anchor" href="#integration-bear-sauvegarde-automatique-des-plans-approuves" aria-label="Permalink to &quot;Intégration Bear : Sauvegarde automatique des plans approuvés&quot;">​</a></h1><h2 id="ce-que-vous-apprendrez" tabindex="-1">Ce que vous apprendrez <a class="header-anchor" href="#ce-que-vous-apprendrez" aria-label="Permalink to &quot;Ce que vous apprendrez&quot;">​</a></h2><p>Une fois l&#39;intégration Bear activée, chaque fois que vous approuvez un plan, Plannotator l&#39;enregistre automatiquement dans votre Bear, notamment :</p><ul><li>Un titre généré automatiquement (extrait du plan)</li><li>Des tags intelligents (nom du projet, mots-clés, langage de programmation)</li><li>Le contenu complet du plan</li></ul><p>Ainsi, vous pouvez gérer tous les plans approuvés en un seul endroit, facilitant la consultation ultérieure et la capitalisation des connaissances.</p><h2 id="le-probleme-que-vous-rencontrez" tabindex="-1">Le problème que vous rencontrez <a class="header-anchor" href="#le-probleme-que-vous-rencontrez" aria-label="Permalink to &quot;Le problème que vous rencontrez&quot;">​</a></h2><p>Vous avez peut-être rencontré ces situations :</p><ul><li>L&#39;IA génère un excellent plan, mais vous souhaitez le sauvegarder pour référence future</li><li>Copier-coller manuellement les plans dans Bear est fastidieux</li><li>Les plans de différents projets sont mélangés, sans gestion par tags</li></ul><p>Avec l&#39;intégration Bear, ces problèmes sont résolus automatiquement.</p><h2 id="quand-utiliser-cette-fonctionnalite" tabindex="-1">Quand utiliser cette fonctionnalité <a class="header-anchor" href="#quand-utiliser-cette-fonctionnalite" aria-label="Permalink to &quot;Quand utiliser cette fonctionnalité&quot;">​</a></h2><ul><li>Vous utilisez Bear comme application de notes principale</li><li>Vous devez archiver les plans approuvés dans une base de connaissances</li><li>Vous souhaitez récupérer rapidement les plans historiques via des tags</li></ul><div class="info custom-block"><p class="custom-block-title">À propos de Bear</p><p>Bear est une application de notes Markdown pour macOS, prenant en charge les tags, le chiffrement, la synchronisation et d&#39;autres fonctionnalités. Si vous ne l&#39;avez pas encore installée, visitez <a href="https://bear.app/" target="_blank" rel="noreferrer">bear.app</a> pour en savoir plus.</p></div><h2 id="🎒-prerequis" tabindex="-1">🎒 Prérequis <a class="header-anchor" href="#🎒-prerequis" aria-label="Permalink to &quot;🎒 Prérequis&quot;">​</a></h2><ul><li>Plannotator installé (voir le <a href="./../../start/installation-claude-code/">tutoriel d&#39;installation</a>)</li><li>Bear installé et fonctionnel</li><li>Connaissance de base du processus d&#39;évaluation des plans (voir les <a href="./../../platforms/plan-review-basics/">bases de l&#39;évaluation des plans</a>)</li></ul><h2 id="concept-cle" tabindex="-1">Concept clé <a class="header-anchor" href="#concept-cle" aria-label="Permalink to &quot;Concept clé&quot;">​</a></h2><p>Le cœur de l&#39;intégration Bear est le protocole <strong>x-callback-url</strong> :</p><ol><li>Dans l&#39;interface UI de Plannotator, activez l&#39;intégration Bear (stockée dans le localStorage du navigateur)</li><li>Lors de l&#39;approbation d&#39;un plan, Plannotator envoie l&#39;URL <code>bear://x-callback-url/create</code></li><li>Le système utilise la commande <code>open</code> pour ouvrir automatiquement Bear et créer une note</li><li>Le contenu du plan, le titre et les tags sont automatiquement remplis</li></ol><p><strong>Points clés</strong> :</p><ul><li>Aucune configuration de chemin de vault nécessaire (contrairement à Obsidian qui nécessite de spécifier un vault)</li><li>Génération intelligente de tags (maximum 7)</li><li>Sauvegarde automatique lors de l&#39;approbation du plan</li></ul><div class="tip custom-block"><p class="custom-block-title">Différence avec Obsidian</p><p>L&#39;intégration Bear est plus simple, ne nécessitant pas la configuration d&#39;un chemin de vault, juste un interrupteur. Cependant, Obsidian permet de spécifier le dossier de sauvegarde et offre plus de personnalisation.</p></div><h2 id="tutoriel-etape-par-etape" tabindex="-1">Tutoriel étape par étape <a class="header-anchor" href="#tutoriel-etape-par-etape" aria-label="Permalink to &quot;Tutoriel étape par étape&quot;">​</a></h2><h3 id="etape-1-ouvrir-les-parametres-de-plannotator" tabindex="-1">Étape 1 : Ouvrir les paramètres de Plannotator <a class="header-anchor" href="#etape-1-ouvrir-les-parametres-de-plannotator" aria-label="Permalink to &quot;Étape 1 : Ouvrir les paramètres de Plannotator&quot;">​</a></h3><p>Une fois que l&#39;Agent IA a généré un plan et ouvert l&#39;interface UI de Plannotator, cliquez sur le bouton ⚙️ <strong>Settings</strong> en haut à droite.</p><p><strong>Ce que vous devriez voir</strong> : Le panneau des paramètres apparaît, contenant plusieurs options de configuration</p><h3 id="etape-2-activer-l-integration-bear" tabindex="-1">Étape 2 : Activer l&#39;intégration Bear <a class="header-anchor" href="#etape-2-activer-l-integration-bear" aria-label="Permalink to &quot;Étape 2 : Activer l&#39;intégration Bear&quot;">​</a></h3><p>Dans le panneau des paramètres, trouvez la section <strong>Bear Notes</strong> et cliquez sur l&#39;interrupteur.</p><p><strong>Pourquoi</strong> L&#39;interrupteur passe du gris (désactivé) au bleu (activé), tout en étant stocké dans le localStorage du navigateur.</p><p><strong>Ce que vous devriez voir</strong> :</p><ul><li>L&#39;interrupteur Bear Notes devient bleu</li><li>Texte descriptif : &quot;Auto-save approved plans to Bear&quot;</li></ul><h3 id="etape-3-approuver-le-plan" tabindex="-1">Étape 3 : Approuver le plan <a class="header-anchor" href="#etape-3-approuver-le-plan" aria-label="Permalink to &quot;Étape 3 : Approuver le plan&quot;">​</a></h3><p>Une fois l&#39;évaluation du plan terminée, cliquez sur le bouton <strong>Approve</strong> en bas.</p><p><strong>Pourquoi</strong> Plannotator lit les paramètres Bear, et si activé, appelle le x-callback-url de Bear lors de l&#39;approbation.</p><p><strong>Ce que vous devriez voir</strong> :</p><ul><li>L&#39;application Bear s&#39;ouvre automatiquement</li><li>Une fenêtre de nouvelle note apparaît</li><li>Le titre et le contenu sont déjà remplis</li><li>Les tags sont déjà générés (commençant par <code>#</code>)</li></ul><h3 id="etape-4-consulter-la-note-sauvegardee" tabindex="-1">Étape 4 : Consulter la note sauvegardée <a class="header-anchor" href="#etape-4-consulter-la-note-sauvegardee" aria-label="Permalink to &quot;Étape 4 : Consulter la note sauvegardée&quot;">​</a></h3><p>Dans Bear, vérifiez la note nouvellement créée et confirmez :</p><ul><li>Le titre est correct (provenant du H1 du plan)</li><li>Le contenu est complet (contient le texte complet du plan)</li><li>Les tags sont raisonnables (nom du projet, mots-clés, langage de programmation)</li></ul><p><strong>Ce que vous devriez voir</strong> : Une structure de note similaire à celle-ci :</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## User Authentication</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[Contenu complet du plan...]</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">#plannotator #myproject #authentication #typescript #api</span></span></code></pre></div><h2 id="points-de-verification-✅" tabindex="-1">Points de vérification ✅ <a class="header-anchor" href="#points-de-verification-✅" aria-label="Permalink to &quot;Points de vérification ✅&quot;">​</a></h2><ul><li>[ ] L&#39;interrupteur Bear Notes dans les paramètres est activé</li><li>[ ] Bear s&#39;ouvre automatiquement après l&#39;approbation du plan</li><li>[ ] Le titre de la note correspond au H1 du plan</li><li>[ ] La note contient le contenu complet du plan</li><li>[ ] Les tags incluent <code>#plannotator</code> et le nom du projet</li></ul><h2 id="depannage" tabindex="-1">Dépannage <a class="header-anchor" href="#depannage" aria-label="Permalink to &quot;Dépannage&quot;">​</a></h2><h3 id="bear-ne-s-ouvre-pas-automatiquement" tabindex="-1">Bear ne s&#39;ouvre pas automatiquement <a class="header-anchor" href="#bear-ne-s-ouvre-pas-automatiquement" aria-label="Permalink to &quot;Bear ne s&#39;ouvre pas automatiquement&quot;">​</a></h3><p><strong>Cause</strong> : La commande système <code>open</code> a échoué, peut-être :</p><ul><li>Bear n&#39;est pas installé ou n&#39;a pas été téléchargé depuis l&#39;App Store</li><li>Le schéma d&#39;URL de Bear a été détourné par une autre application</li></ul><p><strong>Solution</strong> :</p><ol><li>Confirmez que Bear est installé correctement</li><li>Testez manuellement dans le terminal : <code>open &quot;bear://x-callback-url/create?title=test&quot;</code></li></ol><h3 id="les-tags-ne-correspondent-pas-aux-attentes" tabindex="-1">Les tags ne correspondent pas aux attentes <a class="header-anchor" href="#les-tags-ne-correspondent-pas-aux-attentes" aria-label="Permalink to &quot;Les tags ne correspondent pas aux attentes&quot;">​</a></h3><p><strong>Cause</strong> : Les tags sont générés automatiquement selon les règles suivantes :</p><ul><li>Obligatoire : <code>#plannotator</code></li><li>Obligatoire : Nom du projet (extrait du nom du dépôt git ou du répertoire)</li><li>Optionnel : Maximum 3 mots-clés extraits du titre H1 (en excluant les mots vides)</li><li>Optionnel : Tags de langage de programmation extraits des blocs de code (en excluant json/yaml/markdown)</li><li>Maximum 7 tags</li></ul><p><strong>Solution</strong> :</p><ul><li>Si les tags ne correspondent pas aux attentes, vous pouvez les modifier manuellement dans Bear</li><li>Si le nom du projet est incorrect, vérifiez la configuration du dépôt git ou le nom du répertoire</li></ul><h3 id="approuve-mais-non-sauvegarde" tabindex="-1">Approuvé mais non sauvegardé <a class="header-anchor" href="#approuve-mais-non-sauvegarde" aria-label="Permalink to &quot;Approuvé mais non sauvegardé&quot;">​</a></h3><p><strong>Cause</strong> :</p><ul><li>L&#39;interrupteur Bear n&#39;est pas activé (vérifiez les paramètres)</li><li>Erreur réseau ou Bear a expiré</li><li>Le contenu du plan est vide</li></ul><p><strong>Solution</strong> :</p><ol><li>Confirmez que l&#39;interrupteur dans les paramètres est bleu (état activé)</li><li>Vérifiez les journaux du terminal pour les erreurs (<code>[Bear] Save failed:</code>)</li><li>Approuvez à nouveau le plan</li></ol><h2 id="mecanisme-de-generation-des-tags" tabindex="-1">Mécanisme de génération des tags <a class="header-anchor" href="#mecanisme-de-generation-des-tags" aria-label="Permalink to &quot;Mécanisme de génération des tags&quot;">​</a></h2><p>Plannotator génère intelligemment des tags pour vous permettre de récupérer rapidement les plans dans Bear. Voici les règles de génération des tags :</p><table tabindex="0"><thead><tr><th>Source du tag</th><th>Exemple</th><th>Priorité</th></tr></thead><tbody><tr><td>Tag fixe</td><td><code>#plannotator</code></td><td>Obligatoire</td></tr><tr><td>Nom du projet</td><td><code>#myproject</code>, <code>#plannotator</code></td><td>Obligatoire</td></tr><tr><td>Mots-clés H1</td><td><code>#authentication</code>, <code>#api</code></td><td>Optionnel (maximum 3)</td></tr><tr><td>Langage de programmation</td><td><code>#typescript</code>, <code>#python</code></td><td>Optionnel</td></tr></tbody></table><p><strong>Liste des mots vides</strong> (non utilisés comme tags) :</p><ul><li><code>the</code>, <code>and</code>, <code>for</code>, <code>with</code>, <code>this</code>, <code>that</code>, <code>from</code>, <code>into</code></li><li><code>plan</code>, <code>implementation</code>, <code>overview</code>, <code>phase</code>, <code>step</code>, <code>steps</code></li></ul><p><strong>Exclusion de langages de programmation</strong> (non utilisés comme tags) :</p><ul><li><code>json</code>, <code>yaml</code>, <code>yml</code>, <code>text</code>, <code>txt</code>, <code>markdown</code>, <code>md</code></li></ul><details class="details custom-block"><summary>Exemple : Processus de génération de tags</summary><p>Supposons que le titre du plan soit &quot;Implementation Plan: User Authentication System in TypeScript&quot;, et que les blocs de code contiennent Python et JSON :</p><ol><li><strong>Tag fixe</strong> : <code>#plannotator</code></li><li><strong>Nom du projet</strong> : <code>#myproject</code> (nom du dépôt git supposé)</li><li><strong>Mots-clés H1</strong> : <ul><li><code>implementation</code> → Exclu (mot vide)</li><li><code>plan</code> → Exclu (mot vide)</li><li><code>user</code> → Conservé → <code>#user</code></li><li><code>authentication</code> → Conservé → <code>#authentication</code></li><li><code>system</code> → Conservé → <code>#system</code></li><li><code>typescript</code> → Conservé → <code>#typescript</code></li></ul></li><li><strong>Langages de programmation</strong> : <ul><li><code>python</code> → Conservé → <code>#python</code></li><li><code>json</code> → Exclu (liste d&#39;exclusion)</li></ul></li></ol><p>Tags finaux : <code>#plannotator #myproject #user #authentication #system #typescript #python</code> (7 tags, limite atteinte)</p></details><h2 id="comparaison-avec-l-integration-obsidian" tabindex="-1">Comparaison avec l&#39;intégration Obsidian <a class="header-anchor" href="#comparaison-avec-l-integration-obsidian" aria-label="Permalink to &quot;Comparaison avec l&#39;intégration Obsidian&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Fonctionnalité</th><th>Intégration Bear</th><th>Intégration Obsidian</th></tr></thead><tbody><tr><td>Complexité de configuration</td><td>Simple (seulement un interrupteur)</td><td>Moyenne (nécessite de choisir le vault et le dossier)</td></tr><tr><td>Stockage</td><td>Dans l&#39;application Bear</td><td>Chemin de vault spécifié</td></tr><tr><td>Nom de fichier</td><td>Géré automatiquement par Bear</td><td><code>Title - Jan 2, 2026 2-30pm.md</code></td></tr><tr><td>Frontmatter</td><td>Aucun (Bear ne le prend pas en charge)</td><td>Oui (created, source, tags)</td></tr><tr><td>Multiplateforme</td><td>macOS uniquement</td><td>macOS/Windows/Linux</td></tr><tr><td>x-callback-url</td><td>✅ Utilisé</td><td>❌ Écriture directe du fichier</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Comment choisir</p><ul><li>Si vous utilisez uniquement macOS et aimez Bear : l&#39;intégration Bear est plus simple</li><li>Si vous avez besoin du multiplateforme ou de chemins de stockage personnalisés : l&#39;intégration Obsidian est plus flexible</li><li>Si vous souhaitez utiliser les deux : vous pouvez les activer simultanément (l&#39;approbation du plan sauvegardera dans les deux emplacements)</li></ul></div><h2 id="resume-de-la-lecon" tabindex="-1">Résumé de la leçon <a class="header-anchor" href="#resume-de-la-lecon" aria-label="Permalink to &quot;Résumé de la leçon&quot;">​</a></h2><ul><li>L&#39;intégration Bear fonctionne via le protocole x-callback-url, configuration simple</li><li>Il suffit d&#39;activer l&#39;interrupteur dans les paramètres, aucun chemin à spécifier</li><li>Sauvegarde automatique dans Bear lors de l&#39;approbation du plan</li><li>Génération intelligente de tags, incluant le nom du projet, les mots-clés, le langage de programmation (maximum 7)</li><li>Comparé à l&#39;intégration Obsidian, Bear est plus simple mais offre moins de fonctionnalités</li></ul><h2 id="apercu-de-la-prochaine-lecon" tabindex="-1">Aperçu de la prochaine leçon <a class="header-anchor" href="#apercu-de-la-prochaine-lecon" aria-label="Permalink to &quot;Aperçu de la prochaine leçon&quot;">​</a></h2><blockquote><p>Dans la prochaine leçon, nous apprendrons le <strong><a href="./../remote-mode/">Mode à distance/Devcontainer</a></strong>.</p><p>Vous découvrirez :</p><ul><li>Comment utiliser Plannotator dans un environnement distant (SSH, devcontainer, WSL)</li><li>Configuration de ports fixes et de redirection de ports</li><li>Ouvrir le navigateur dans l&#39;environnement distant pour consulter la page d&#39;évaluation</li></ul></blockquote><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquez pour voir l&#39;emplacement du code source</strong></summary><blockquote><p>Dernière mise à jour : 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Fonctionnalité</th><th>Chemin du fichier</th><th>Lignes</th></tr></thead><tbody><tr><td>Interface de configuration Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L18-L20" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>18-20</td></tr><tr><td>Sauvegarde vers Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L234-L257" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>234-257</td></tr><tr><td>Extraction des tags</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L34-L74" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>34-74</td></tr><tr><td>Extraction du titre</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/integrations.ts#L94-L105" target="_blank" rel="noreferrer"><code>packages/server/integrations.ts</code></a></td><td>94-105</td></tr><tr><td>Interface des paramètres Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L15-L17" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>15-17</td></tr><tr><td>Lecture des paramètres Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L22-L26" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>22-26</td></tr><tr><td>Sauvegarde des paramètres Bear</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/utils/bear.ts#L31-L33" target="_blank" rel="noreferrer"><code>packages/ui/utils/bear.ts</code></a></td><td>31-33</td></tr><tr><td>Composant UI des paramètres</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/ui/components/Settings.tsx#L496-L518" target="_blank" rel="noreferrer"><code>packages/ui/components/Settings.tsx</code></a></td><td>496-518</td></tr><tr><td>Appel de Bear lors de l&#39;approbation</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/editor/App.tsx#L512-L514" target="_blank" rel="noreferrer"><code>packages/editor/App.tsx</code></a></td><td>512-514</td></tr><tr><td>Traitement Bear côté serveur</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/index.ts#L250-L257" target="_blank" rel="noreferrer"><code>packages/server/index.ts</code></a></td><td>250-257</td></tr></tbody></table><p><strong>Fonctions clés</strong> :</p><ul><li><code>saveToBear(config: BearConfig)</code> : Sauvegarde le plan dans Bear via x-callback-url</li><li><code>extractTags(markdown: string)</code> : Extrait intelligemment les tags du contenu du plan (maximum 7)</li><li><code>extractTitle(markdown: string)</code> : Extrait le titre de la note du titre H1 du plan</li><li><code>getBearSettings()</code> : Lit les paramètres d&#39;intégration Bear depuis le localStorage</li><li><code>saveBearSettings(settings)</code> : Sauvegarde les paramètres d&#39;intégration Bear dans le localStorage</li></ul><p><strong>Constantes clés</strong> :</p><ul><li><code>STORAGE_KEY_ENABLED = &#39;plannotator-bear-enabled&#39;</code> : Nom de la clé des paramètres Bear dans le localStorage</li></ul><p><strong>Format de l&#39;URL Bear</strong> :</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bear</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//x-callback-url/create?title={title}&amp;text={content}&amp;open_note=no</span></span></code></pre></div></details>`,75)])])}const g=t(n,[["render",i]]);export{m as __pageData,g as default};
